import React, { useState, useEffect } from 'react';
import styles from './Hero.module.css';

const NICHES = [
  'High-Tech', 'Maison & Déco', 'Bijoux', 'Beauté',
  'Animaux', 'Fitness', 'Bébé', 'Mode'
];

function getSecsUntilMidnight() {
  const now = new Date();
  const midnight = new Date();
  midnight.setHours(24, 0, 0, 0);
  return Math.max(0, Math.floor((midnight - now) / 1000));
}

function fmtTime(s) {
  const h = Math.floor(s / 3600);
  const m = Math.floor((s % 3600) / 60);
  const sec = s % 60;
  return [h, m, sec].map(v => String(v).padStart(2, '0')).join(':');
}

export default function Hero() {
  const [step, setStep] = useState(1);
  const [email, setEmail] = useState('');
  const [niche, setNiche] = useState('');
  const [firstName, setFirstName] = useState('');
  const [countdown, setCountdown] = useState(getSecsUntilMidnight());

  useEffect(() => {
    const id = setInterval(() => setCountdown(getSecsUntilMidnight()), 1000);
    return () => clearInterval(id);
  }, []);

  const handleStep1 = (e) => {
    e.preventDefault();
    if (email) setStep(2);
  };

  const handleNiche = (n) => {
    setNiche(n);
    setStep(3);
  };

  const handleStep3 = (e) => {
    e.preventDefault();
    if (firstName) setStep(4);
  };

  return (
    <section className={styles.hero}>
      {/* YouTube video background */}
      <div className={styles.videoWrap}>
        <iframe
          className={styles.videoFrame}
          src="https://www.youtube.com/embed/aqz-KE-bpKQ?autoplay=1&mute=1&loop=1&controls=0&showinfo=0&rel=0&iv_load_policy=3&playlist=aqz-KE-bpKQ&modestbranding=1"
          title="bg"
          allow="autoplay"
          tabIndex="-1"
        />
      </div>
      <div className={styles.overlay} />

      <div className={styles.content}>
        <div className={styles.badge}>
          <span className={styles.dot} />
          Partenaire Officiel Shopify
        </div>

        <h1 className={styles.title}>
          Des Experts E-Commerce Créent Ta Boutique Shopify{' '}
          <em>Prête À Vendre En 24H</em>
        </h1>

        <p className={styles.sub}>
          Conçue par des experts, livrée avec 10 produits gagnants, garantie 90 jours vente ou remboursé
        </p>

        <div className={styles.stars}>
          <span className={styles.starRow}>★★★★★</span>
          <strong className={styles.ratingNum}>4.8/5</strong>
          <span className={styles.ratingCount}>(214 avis vérifiés)</span>
        </div>

        <div className={styles.urgency}>
          <span>🔴 Places du jour : <strong>8/12</strong></span>
          <span className={styles.divider} />
          <span>⏱ Expire dans : <strong className={styles.timer}>{fmtTime(countdown)}</strong></span>
        </div>

        <div className={styles.formCard}>
          {step === 1 && (
            <form onSubmit={handleStep1} className={styles.formInner}>
              <p className={styles.formHint}>Entre ton email pour réserver ta place :</p>
              <div className={styles.inputRow}>
                <input
                  type="email"
                  required
                  placeholder="ton@email.com"
                  value={email}
                  onChange={e => setEmail(e.target.value)}
                  className={styles.input}
                />
                <button type="submit" className={styles.btnGold}>
                  Obtenir ma boutique à 37€ →
                </button>
              </div>
            </form>
          )}

          {step === 2 && (
            <div className={styles.formInner}>
              <p className={styles.formHint}>Choisis ta niche e-commerce :</p>
              <div className={styles.nicheGrid}>
                {NICHES.map(n => (
                  <button key={n} className={styles.nicheBtn} onClick={() => handleNiche(n)}>
                    {n}
                  </button>
                ))}
              </div>
            </div>
          )}

          {step === 3 && (
            <form onSubmit={handleStep3} className={styles.formInner}>
              <p className={styles.formHint}>
                Boutique <span className={styles.nicheChosen}>{niche}</span> — Entre ton prénom :
              </p>
              <div className={styles.inputRow}>
                <input
                  type="text"
                  required
                  placeholder="Ton prénom"
                  value={firstName}
                  onChange={e => setFirstName(e.target.value)}
                  className={styles.input}
                />
                <button type="submit" className={styles.btnGold}>
                  On commence la création ! →
                </button>
              </div>
            </form>
          )}

          {step === 4 && (
            <div className={styles.formInner}>
              <div className={styles.success}>
                <span className={styles.successIcon}>🎉</span>
                <div>
                  <strong>Super {firstName} !</strong> On commence la création de ta boutique{' '}
                  <em>{niche}</em>. Vérifie ta boîte mail : {email}
                </div>
              </div>
            </div>
          )}

          <div className={styles.steps}>
            {[1, 2, 3].map(i => (
              <div
                key={i}
                className={`${styles.stepDot} ${step > i ? styles.stepDone : ''} ${step === i ? styles.stepActive : ''}`}
              />
            ))}
          </div>
        </div>

        <div className={styles.priceRow}>
          <span className={styles.priceOld}>1 885€</span>
          <span className={styles.priceNew}>37€</span>
          <span className={styles.priceNote}>aujourd'hui seulement</span>
        </div>
      </div>
    </section>
  );
}
